(* Uses the Random module *)
(* Initialize the random number generator (usually once) *)
let () = Random.self_init () (* Seed with time/entropy *)
(* Or: Random.init 12345 for a fixed seed *)

let () =
  print_endline "--- Random Numbers ---";

  (* Generate a random integer between 0 (inclusive) and n (exclusive) *)
  let max_exclusive = 101 in (* To get ints up to 100 *)
  let random_int_upto = Random.int max_exclusive in (* [0, n-1] *)
  Printf.printf "Random Integer [0-%d]: %d\n" (max_exclusive - 1) random_int_upto;

  (* Generate a random integer within a range [min, max] (inclusive) *)
  (* Formula: Random.int (max - min + 1) + min *)
  let min_val = 10 in
  let max_val = 20 in
  let range_size = max_val - min_val + 1 in
  let random_int_range = Random.int range_size + min_val in
  Printf.printf "Random Integer [%d-%d]: %d\n" min_val max_val random_int_range;

  (* Generate a random float between 0.0 (inclusive) and bound (exclusive) *)
  let float_bound = 1.0 in
  let random_float = Random.float float_bound in
  Printf.printf "Random Float [0.0, %.1f): %f\n" float_bound random_float;

  (* Select a random element from an array *)
  let fruits = [|"apple"; "banana"; "cherry"|] in (* Array literal *)
  if Array.length fruits > 0 then
    let random_index = Random.int (Array.length fruits) in
    let random_fruit = fruits.(random_index) in (* Array access with .() *)
    Printf.printf "Random fruit: %s\n" random_fruit
  else
    print_endline "Fruit array is empty."

reverseString:
(* Requires String, List, Seq modules (Seq available OCaml 4.07+) *)
(* For older OCaml, manual string -> list -> string needed *)

(* Helper function to convert string to list of chars *)
let chars_of_string s = List.of_seq (String.to_seq s)

(* Helper function to convert list of chars to string *)
let string_of_chars cl = String.of_seq (List.to_seq cl)

(* Function to reverse a string (handles multi-byte UTF-8 chars correctly) *)
let reverse_string s =
  s |> chars_of_string |> List.rev |> string_of_chars

let () =
  let original_string = "OCaml Functional" in
  print_endline ("Original: " ^ original_string);
  let reversed_str = reverse_string original_string in
  print_endline ("Reversed: " ^ reversed_str);

