fibonacci:
(* Calculate Nth Fibonacci number (0-indexed) *)
(* Uses Int64 for a larger range than default int *)
(* For arbitrary precision, use Zarith or other BigInt library *)

let rec fibonacci n =
  let open Int64 in (* Use Int64 operators locally *)
  if n < 0L then invalid_arg "fibonacci: input must be non-negative"
  else
    let rec fib_acc k (a, b) =
      if k = 0L then a
      else fib_acc (sub k 1L) (b, add a b)
    in
    fib_acc n (0L, 1L) (* Tail recursive helper *)

(* Function to generate first 'count' Fibonacci numbers *)
let generate_fib_sequence count =
   if count < 0 then invalid_arg "generate_fib_sequence: count must be non-negative"
   else List.init count (fun i -> fibonacci (Int64.of_int i)) (* List.init needs int *)

let () =
  let n = 10 in
  Printf.printf "Fibonacci number F(%d): %Ld\n" n (fibonacci (Int64.of_int n));

  let num_terms = 15 in
  Printf.printf "First %d Fibonacci numbers:\n" num_terms;
  let sequence = generate_fib_sequence num_terms in
  print_endline ("[" ^ (String.concat ", " (List.map Int64.to_string sequence)) ^ "]");

  (* Example with large number *)
  let large_n = 90 in (* Fits within Int64 *)
  Printf.printf "Fibonacci number F(%d): %Ld\n" large_n (fibonacci (Int64.of_int large_n))

factorial:
(* Calculate Factorial N! *)
(* Uses Int64 for a larger range. Use Zarith library for arbitrary precision. *)

(* Tail recursive factorial using an accumulator *)
let factorial n =
  let open Int64 in (* Use Int64 operators locally *)
  if n < 0L then invalid_arg "factorial: input must be non-negative"
  else
    let rec fact_acc k acc =
      if k <= 1L then acc (* Factorial of 0 and 1 is 1 *)
      else fact_acc (sub k 1L) (mul acc k)
    in
    fact_acc n 1L

