primeCheck:
(* Function to check if a number is prime *)
(* Uses Int64 for wider range *)

let is_prime (n: int64) : bool =
  let open Int64 in (* Use Int64 operators locally *)
  if n <= 1L then false
  else if n <= 3L then true
  else if n mod 2L = 0L || n mod 3L = 0L then false
  else
    let limit = floor (sqrt (to_float n)) |> Int64.of_float in
    let rec check i =
      if i > limit then true (* Checked all divisors up to limit *)
      else if n mod i = 0L || n mod (add i 2L) = 0L then false (* Divisor found *)
      else check (add i 6L) (* Check next pair *)
    in
    check 5L (* Start checking from 5 *)

let () =
  let numbers_to_check = [2L; 3L; 4L; 17L; 25L; 29L; 97L; 100L; 1L; -5L; 1000000007L] in

  List.iter (fun n ->
    if is_prime n then
      Printf.printf "%Ld is prime.\n" n
    else
      Printf.printf "%Ld is not prime.\n" n
  ) numbers_to_check

readFile:
(* Read content from a file using Stdlib I/O *)
open Stdlib (* Ensure access to Pervasives like open_in, input_line etc. *)

(* Function to read all lines from a file *)
let read_all_lines file_path =
  let lines = ref [] in
  try
    let chan = open_in file_path in (* Open for reading *)
    try
      while true do
        lines := input_line chan :: !lines (* Prepend line to list *)
      done;
      !lines (* Should not be reached *)
    with End_of_file ->
      close_in chan; (* Close on EOF *)
      List.rev !lines (* Reverse list to get original order *)
    with ex -> (* Handle other potential errors during read *)
      close_in_noerr chan; (* Attempt to close even if error *)
      raise ex (* Re-raise the exception *)
  with Sys_error msg -> (* Handle file opening errors *)
    Printf.eprintf "Error opening file '%s': %s\n" file_path msg;
    [] (* Return empty list on error *)

(* Function to read entire file (less common for large files in stdlib) *)
let read_all_content file_path =
  try
    let chan = open_in file_path in
    let size = LargeFile.in_channel_length chan in (* Get file size *)
    let content = Bytes.create size in (* Create mutable byte sequence *)
    really_input chan content 0 size; (* Read exactly size bytes *)
    close_in chan;
    Bytes.to_string content (* Convert bytes to immutable string *)
  with Sys_error msg ->
    Printf.eprintf "Error reading file '%s': %s\n" file_path msg;
    "" (* Return empty string on error *)
  | End_of_file -> (* Should not happen with really_input unless size was wrong *)
      Printf.eprintf "Error reading file '%s': Unexpected EOF\n" file_path;
      ""


