writeFile:
(* Write or append text content to a file using Stdlib I/O *)
open Stdlib

(* Helper function for safe file writing/appending *)
let safe_file_op file_path mode action =
  try
    let chan = open_out_gen mode 0o664 file_path in (* 0o664 are typical permissions *)
    try
      action chan; (* Perform the write/append action *)
      close_out chan
    with ex ->
      close_out_noerr chan; (* Close even if action failed *)
      raise ex
  with Sys_error msg ->
    Printf.eprintf "Error accessing file '%s' (mode %s): %s\n" file_path (match mode with Open_wronly :: _ -> "write" | Open_append :: _ -> "append" | _ -> "?") msg

(* Write (overwrite) a list of lines *)
let write_lines file_path lines =
  safe_file_op file_path [Open_wronly; Open_creat; Open_trunc] (fun chan ->
      List.iter (fun line -> output_string chan (line ^ "\n")) lines
  )

(* Append a list of lines *)
let append_lines file_path lines =
   safe_file_op file_path [Open_wronly; Open_creat; Open_append] (fun chan ->
       List.iter (fun line -> output_string chan (line ^ "\n")) lines
   )


