fileExists:
(* Check if a file or directory exists using Sys module *)
open Sys (* Provides file_exists, is_directory *)

let check_path path =
  Printf.printf "Checking: '%s'\n" path;
  let exists = file_exists path in
  if exists then
      try (* is_directory can raise Sys_error if path disappears or permission issue *)
          if is_directory path then
              Printf.printf " -> Exists as a DIRECTORY.\n"
          else
              Printf.printf " -> Exists as a FILE.\n"
      with Sys_error _ ->
          Printf.printf " -> Exists, but type could not be determined (permission issue?).\n"
  else
      Printf.printf " -> Does NOT exist.\n"


