dateTime:
(* Get and format date/time using Unix module *)
open Unix (* Provides time(), localtime(), gmtime(), mktime(), strftime requires external lib *)
(* Formatting uses standard library access to the 'tm' record *)

(* Helper function to format tm record *)
let format_tm tm =
  Printf.sprintf "%d-%02d-%02d %02d:%02d:%02d"
    (tm.tm_year + 1900) (tm.tm_mon + 1) tm.tm_mday (* year since 1900, mon 0-11 *)
    tm.tm_hour tm.tm_min tm.tm_sec

let () =
    print_endline "--- Current Date and Time ---";

    (* Get current time as seconds since epoch (float) *)
    let epoch_seconds_float = Unix.time () in
    Printf.printf "Seconds since epoch (float): %f\n" epoch_seconds_float;
    let epoch_seconds_int = Int64.of_float epoch_seconds_float in
    Printf.printf "Seconds since epoch (int64): %Ld\n" epoch_seconds_int;

    (* Convert epoch seconds to local time structure (tm record) *)
    let local_tm = Unix.localtime epoch_seconds_float in
    print_endline "\n--- Local Time Components (from Unix.localtime) ---";
    Printf.printf "Year: %d\n" (local_tm.tm_year + 1900);
    Printf.printf "Month: %d\n" (local_tm.tm_mon + 1); (* 0-11 -> 1-12 *)
    Printf.printf "Day: %d\n" local_tm.tm_mday;
    Printf.printf "Hour: %d\n" local_tm.tm_hour;
    Printf.printf "Minute: %d\n" local_tm.tm_min;
    Printf.printf "Second: %d\n" local_tm.tm_sec;
    Printf.printf "DayOfWeek: %d (0=Sun)\n" local_tm.tm_wday;
    Printf.printf "DayOfYear: %d (0-365)\n" local_tm.tm_yday;
    Printf.printf "Is DST?: %b\n" local_tm.tm_isdst;

    (* Convert epoch seconds to UTC time structure *)
    let utc_tm = Unix.gmtime epoch_seconds_float in
    Printf.printf "\nUTC Hour: %d\n" utc_tm.tm_hour;

    print_endline "\n--- Basic Formatting (manual from tm record) ---";
    print_endline ("Formatted Local Time: " ^ format_tm local_tm);
    print_endline ("Formatted UTC Time: " ^ format_tm utc_tm);

    (* Note: For strftime-like formatting, external libraries like *)
    (* 'calendar' (older) or 'ISO8601' are typically used in OCaml. *)
