maxInArray:
(* Find the maximum value in an OCaml list or array *)

(* Function to find max in a list using List.fold_left *)
(* Returns an option type: Some max or None if list is empty *)
let list_max list =
  match list with
  | [] -> None (* Handle empty list *)
  | h :: t -> Some (List.fold_left max h t) (* Use built-in max, requires initial element *)

(* Function to find max in an array using Array.fold_left *)
let array_max arr =
  if Array.length arr = 0 then None
  else Some (Array.fold_left max arr.(0) (Array.sub arr 1 (Array.length arr - 1)))
  (* Simpler way if we assume non-empty for snippet? *)
  (* let array_max_simple arr = Array.fold_left max arr.(0) arr *)


